const chatId = $('Start').first().json.tool_input.chat_id;
const address = $('Start').first().json.tool_input.address || '';

const cartItems = $('Get Cart Items').all().map(i => i.json).filter(i => i && i.sku);
const invMap = {};
$('Get Inventory').all().forEach(i => { invMap[i.json.sku] = i.json; });
const promotions = $('Get Active Promotions').all().map(i => i.json);

const orderItems = cartItems.map(item => {
  const p = invMap[item.sku] || {};
  const qty = parseFloat(item.quantity);
  const price = parseFloat(item.price_at_addition);
  return {
    sku: item.sku,
    original_name: p.item_name || item.sku,
    category: p.category || '',
    quantity: qty,
    unit: p.unit || '',
    unit_price: price,
    line_total: qty * price
  };
});

const subtotal = orderItems.reduce((s, i) => s + i.line_total, 0);

const now = new Date();
const validPromos = promotions.filter(p => {
  if (!p.is_active) return false;
  try {
    if (p.valid_from && now < new Date(p.valid_from)) return false;
    if (p.valid_until && now > new Date(p.valid_until)) return false;
  } catch(e) { return false; }
  return true;
});

let totalDiscount = 0;
const appliedPromos = [];

// Product-level
validPromos.filter(p => p.promo_scope === 'product').forEach(promo => {
  const item = orderItems.find(i => i.sku === promo.target_sku);
  if (!item) return;
  let discount = 0;
  if (promo.discount_type === 'percentage') {
    discount = item.line_total * (Number(promo.discount_value) / 100);
  } else if (promo.discount_type === 'flat') {
    discount = Math.min(Number(promo.discount_value), item.line_total);
  } else if (promo.discount_type === 'bogo') {
    const freeQty = Math.floor(item.quantity / 3);
    discount = freeQty * item.unit_price;
  }
  if (discount > 0) {
    totalDiscount += discount;
    appliedPromos.push({ code: promo.promo_code, description: promo.description, amount: discount });
  }
});

// Category-level — flat applied ONCE on category total
validPromos.filter(p => p.promo_scope === 'category').forEach(promo => {
  const catTotal = orderItems
    .filter(i => i.category === promo.target_category)
    .reduce((s, i) => s + i.line_total, 0);
  if (catTotal === 0) return;
  let discount = 0;
  if (promo.discount_type === 'percentage') {
    discount = catTotal * (Number(promo.discount_value) / 100);
  } else if (promo.discount_type === 'flat') {
    discount = Math.min(Number(promo.discount_value), catTotal);
  }
  if (discount > 0) {
    totalDiscount += discount;
    appliedPromos.push({ code: promo.promo_code, description: promo.description, amount: discount });
  }
});

// Order-level — on subtotal after above discounts
const afterItemDiscounts = Math.max(0, subtotal - totalDiscount);
validPromos.filter(p => p.promo_scope === 'order').forEach(promo => {
  let discount = 0;
  if (promo.discount_type === 'percentage') {
    discount = afterItemDiscounts * (Number(promo.discount_value) / 100);
  } else if (promo.discount_type === 'flat') {
    discount = Math.min(Number(promo.discount_value), afterItemDiscounts);
  }
  if (discount > 0) {
    totalDiscount += discount;
    appliedPromos.push({ code: promo.promo_code, description: promo.description, amount: discount });
  }
});

const finalTotal = Math.max(0, subtotal - totalDiscount);
const cartId = $('Get Active Cart').first().json.cart_id;
const orderId = 'ORD-' + chatId + '-' + Date.now();

// order_details_json stores everything — used by payment webhook and kirana notification
const orderDetailsJson = {
  order_id: orderId,
  chat_id: chatId,
  address: address,
  store_id: 1,
  items_in_final_order: orderItems,
  subtotal_before_discounts: subtotal,
  total_discount_applied: totalDiscount,
  final_order_total: finalTotal,
  applied_promos: appliedPromos
};

return [{
  json: {
    order_id: orderId,
    cart_id: cartId,
    chat_id: chatId,
    address: address,
    store_id: 1,
    subtotal: subtotal,
    total_discount: totalDiscount,
    final_total: finalTotal,
    items: orderItems,
    applied_promos: appliedPromos,
    order_details_json: JSON.stringify(orderDetailsJson)
  }
}];

function esc(t){return String(t||'').replace(/[_*[\]()~`>#+\-=|{}.!]/g,'\\$&');}
const calc = $('Calculate Order').first().json;
const lines = calc.items.map(i => {
  const unit = i.unit ? ' ' + i.unit : '';
  return '- ' + esc(i.original_name) + ' x ' + i.quantity + unit + ' = Rs.' + i.line_total.toFixed(2);
});
const promoLines = calc.applied_promos.length > 0
  ? '\n' + calc.applied_promos.map(p => esc(p.code) + ': -Rs.' + p.amount.toFixed(2)).join('\n')
  : '';
const savings = calc.total_discount > 0 ? '\nTotal Savings: -Rs.' + esc(calc.total_discount.toFixed(2)) : '';
const msg =
  'Order Summary\n\n' +
  lines.join('\n') +
  promoLines +
  '\n\nDeliver to: ' + esc(calc.address) +
  '\nSubtotal: Rs.' + esc(calc.subtotal.toFixed(2)) +
  savings +
  '\nTotal Payable: Rs.' + esc(calc.final_total.toFixed(2)) +
  '\n\n' + esc('Reply pay to proceed to payment or cancel to cancel.');
return [{ json: { confirmation_message: msg, chat_id: calc.chat_id } }];
